// UpsertSetlist inserts or updates a setlist in the dedicated table.
func (s *Store) UpsertSetlist(id, artistMBID, artistName, venueID, venueName, cityName, countryCode, eventDate, tourName, url, versionID, lastUpdated string, songCount, encoreCount int) error {
	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	_, err := s.db.Exec(
		`INSERT INTO setlists (id, artist_mbid, artist_name, venue_id, venue_name, city_name, country_code, event_date, tour_name, url, version_id, last_updated, song_count, encore_count, synced_at)
		 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
		 ON CONFLICT(id) DO UPDATE SET artist_mbid=excluded.artist_mbid, artist_name=excluded.artist_name,
		 venue_id=excluded.venue_id, venue_name=excluded.venue_name, city_name=excluded.city_name,
		 country_code=excluded.country_code, event_date=excluded.event_date, tour_name=excluded.tour_name,
		 url=excluded.url, version_id=excluded.version_id, last_updated=excluded.last_updated,
		 song_count=excluded.song_count, encore_count=excluded.encore_count, synced_at=excluded.synced_at`,
		id, artistMBID, artistName, venueID, venueName, cityName, countryCode, eventDate, tourName, url, versionID, lastUpdated, songCount, encoreCount,
	)
	return err
}

// UpsertSong inserts a song into the dedicated table. Songs are keyed by
// (setlist_id, set_number, position) to avoid duplicates on re-sync.
func (s *Store) UpsertSong(setlistID string, setNumber, position int, name, info string, isCover bool, coverArtistName, coverArtistMBID, withArtistName, withArtistMBID string, isTape, isEncore bool) error {
	s.writeMu.Lock()
	defer s.writeMu.Unlock()
	boolToInt := func(b bool) int {
		if b {
			return 1
		}
		return 0
	}
	// Delete any existing song at this position to handle re-syncs
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()
	if _, err := tx.Exec(`DELETE FROM songs WHERE setlist_id=? AND set_number=? AND position=?`, setlistID, setNumber, position); err != nil {
		return err
	}
	if _, err := tx.Exec(
		`INSERT INTO songs (setlist_id, set_number, position, name, info, is_cover, cover_artist_name, cover_artist_mbid, with_artist_name, with_artist_mbid, is_tape, is_encore)
		 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
		setlistID, setNumber, position, name, info,
		boolToInt(isCover), coverArtistName, coverArtistMBID,
		withArtistName, withArtistMBID,
		boolToInt(isTape), boolToInt(isEncore),
	); err != nil {
		return err
	}
	return tx.Commit()
}

